import { useEffect, useState } from 'react';
import { Pencil, Trash2, Plus } from 'lucide-react';

export default function PlateformeManagementContent() {
  const [plateformes, setPlateformes] = useState([]);
  const [formData, setFormData] = useState({ nom: '', description: '' });
  const [editingId, setEditingId] = useState(null);

  const API_URL = 'http://localhost:5000/plateformes';

  // Charger les plateformes
  useEffect(() => {
    fetch(API_URL)
      .then((res) => res.json())
      .then((data) => setPlateformes(data))
      .catch((err) => console.error('Erreur de chargement:', err));
  }, []);

  // Soumettre (création ou mise à jour)
  const handleSubmit = async (e) => {
    e.preventDefault();
    const method = editingId ? 'PUT' : 'POST';
    const url = editingId ? `${API_URL}/${editingId}` : API_URL;

    const response = await fetch(url, {
      method,
      headers: { 'Content-Type': 'application/json' },
      body: JSON.stringify(formData),
    });

    const result = await response.json();
    if (response.ok) {
      setFormData({ nom: '', description: '' });
      setEditingId(null);
      refreshList();
    } else {
      alert(result.message || 'Erreur lors de la soumission');
    }
  };

  // Supprimer
  const handleDelete = async (id) => {
    if (window.confirm('Supprimer cette plateforme ?')) {
      const res = await fetch(`${API_URL}/${id}`, { method: 'DELETE' });
      if (res.ok) refreshList();
    }
  };

  // Préparer l'édition
  const handleEdit = (plateforme) => {
    setFormData({ nom: plateforme.nom, description: plateforme.description });
    setEditingId(plateforme.id);
  };

  // Rafraîchir
  const refreshList = () => {
    fetch(API_URL)
      .then((res) => res.json())
      .then((data) => setPlateformes(data));
  };

  return (
    <div className="p-6">
      <h1 className="text-2xl font-bold text-gray-800 mb-4">Plateformes Management</h1>

      {/* Formulaire */}
      <form onSubmit={handleSubmit} className="mb-6 grid grid-cols-3 gap-4">
        <input
          type="text"
          placeholder="Nom"
          className="border p-2 rounded"
          value={formData.nom}
          onChange={(e) => setFormData({ ...formData, nom: e.target.value })}
          required
        />
        <input
          type="text"
          placeholder="Description"
          className="border p-2 rounded"
          value={formData.description}
          onChange={(e) =>
            setFormData({ ...formData, description: e.target.value })
          }
        />
        <button
          type="submit"
          className="bg-blue-800 text-white rounded px-4 py-2 flex items-center justify-center"
        >
          <Plus size={16} className="mr-1" />
          {editingId ? 'Modifier' : 'Ajouter'}
        </button>
      </form>

      {/* Liste des plateformes */}
      <table className="w-full border-collapse">
        <thead>
          <tr className="bg-gray-100 text-left">
            <th className="py-3 px-4 text-left text-sm font-medium text-gray-500 cursor-pointer">Nom</th>
            <th className="py-3 px-4 text-left text-sm font-medium text-gray-500 cursor-pointer">Description</th>
            <th className="py-3 px-4 text-left text-sm font-medium text-gray-500 cursor-pointer">Date de création</th>
            <th className="py-3 px-4 text-left text-sm font-medium text-gray-500 cursor-pointer">Actif</th>
            <th className="py-3 px-4 text-left text-sm font-medium text-gray-500 cursor-pointer text-center">Actions</th>
          </tr>
        </thead>
        <tbody>
          {plateformes.map((p) => (
            <tr key={p.id} className="border-b hover:bg-gray-50 relative">
              <td className="py-3 px-4 text-sm text-gray-700">{p.nom}</td>
              <td className="py-3 px-4 text-sm text-gray-700">{p.description}</td>
              <td className="py-3 px-4 text-sm text-gray-700">{p.date_creation}</td>
              <td className="py-3 px-4 text-sm text-gray-700">{p.actif ? '✅' : '❌'}</td>
              <td className="py-3 px-4 text-sm text-gray-700 text-center">
                <button
                  className="text-blue-600 mr-2"
                  onClick={() => handleEdit(p)}
                >
                  <Pencil size={18} />
                </button>
                <button
                  className="text-red-600"
                  onClick={() => handleDelete(p.id)}
                >
                  <Trash2 size={18} />
                </button>
              </td>
            </tr>
          ))}
        </tbody>
      </table>
    </div>
  );
}
